/**
 * Interactive Feature Wall Property Panel
 * Author: generated by Amazon Q
 * Created: 2024-12-22
 */

'use client';

import React from 'react';
import { SectionConfig } from '@/lib/page-builder/section-schemas';
import { Plus, Trash2, Upload, Eye, EyeOff, Move } from 'lucide-react';

interface InteractiveFeatureWallPropertyPanelProps {
  section: SectionConfig;
  onUpdate: (updates: Partial<SectionConfig>) => void;
}

const iconOptions = [
  { value: 'check', label: 'Check Circle' },
  { value: 'doc', label: 'Document' },
  { value: 'calendar', label: 'Calendar' },
  { value: 'users', label: 'Users' },
  { value: 'chart', label: 'Chart' },
  { value: 'settings', label: 'Settings' },
  { value: 'zap', label: 'Lightning' },
  { value: 'shield', label: 'Shield' },
  { value: 'globe', label: 'Globe' },
  { value: 'smartphone', label: 'Smartphone' },
  { value: 'database', label: 'Database' },
  { value: 'cloud', label: 'Cloud' },
];

export function InteractiveFeatureWallPropertyPanel({
  section,
  onUpdate,
}: InteractiveFeatureWallPropertyPanelProps) {
  const data = section.data || {};
  const features = data.features || [];

  const updateData = (newData: any) => {
    onUpdate({
      ...section,
      data: { ...data, ...newData },
    });
  };

  const addFeature = () => {
    const newFeature = {
      id: `feature-${Date.now()}`,
      key: `feature-${features.length + 1}`,
      title: 'New Feature',
      icon: 'check' as const,
      previewImage: '',
      description: '',
    };

    updateData({
      features: [...features, newFeature],
    });
  };

  const updateFeature = (index: number, updates: any) => {
    const updatedFeatures = features.map((feature: any, i: number) =>
      i === index ? { ...feature, ...updates } : feature
    );
    updateData({ features: updatedFeatures });
  };

  const removeFeature = (index: number) => {
    const updatedFeatures = features.filter((_: any, i: number) => i !== index);
    updateData({ features: updatedFeatures });
  };

  const moveFeature = (index: number, direction: 'up' | 'down') => {
    const newIndex = direction === 'up' ? index - 1 : index + 1;
    if (newIndex < 0 || newIndex >= features.length) return;

    const updatedFeatures = [...features];
    [updatedFeatures[index], updatedFeatures[newIndex]] = [updatedFeatures[newIndex], updatedFeatures[index]];
    updateData({ features: updatedFeatures });
  };

  return (
    <div className="space-y-6">
      {/* Section Header */}
      <div>
        <h3 className="text-lg font-semibold mb-4">Interactive Feature Wall</h3>
        
        {/* Basic Settings */}
        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium mb-2">Title</label>
            <input
              type="text"
              value={data.title || ''}
              onChange={(e) => updateData({ title: e.target.value })}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-800"
              placeholder="Everything you need in one converged AI platform"
            />
          </div>

          <div>
            <label className="block text-sm font-medium mb-2">Subtitle</label>
            <textarea
              value={data.subtitle || ''}
              onChange={(e) => updateData({ subtitle: e.target.value })}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-800"
              rows={2}
              placeholder="100+ features to maximize human and AI productivity."
            />
          </div>
        </div>
      </div>

      {/* Layout Settings */}
      <div>
        <h4 className="font-medium mb-3">Layout Settings</h4>
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium mb-2">Grid Columns</label>
            <select
              value={data.gridColumns || 3}
              onChange={(e) => updateData({ gridColumns: parseInt(e.target.value) })}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-800"
            >
              <option value={2}>2 Columns</option>
              <option value={3}>3 Columns</option>
              <option value={4}>4 Columns</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium mb-2">Preview Aspect</label>
            <select
              value={data.previewAspectRatio || 'video'}
              onChange={(e) => updateData({ previewAspectRatio: e.target.value })}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-800"
            >
              <option value="square">Square (1:1)</option>
              <option value="video">Video (16:9)</option>
              <option value="wide">Wide (21:9)</option>
            </select>
          </div>
        </div>

        <div className="mt-4 space-y-3">
          <div>
            <label className="block text-sm font-medium mb-2">Theme</label>
            <select
              value={data.theme || 'light'}
              onChange={(e) => updateData({ theme: e.target.value })}
              className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-800"
            >
              <option value="light">Light</option>
              <option value="dark">Dark</option>
              <option value="gradient">Gradient</option>
            </select>
          </div>

          <div className="flex items-center space-x-2">
            <input
              type="checkbox"
              id="showDescriptions"
              checked={data.showDescriptions || false}
              onChange={(e) => updateData({ showDescriptions: e.target.checked })}
              className="rounded"
            />
            <label htmlFor="showDescriptions" className="text-sm font-medium">
              Show Descriptions
            </label>
          </div>
        </div>
      </div>

      {/* Features Management */}
      <div>
        <div className="flex items-center justify-between mb-4">
          <h4 className="font-medium">Feature Tiles</h4>
          <button
            onClick={addFeature}
            className="flex items-center space-x-1 px-3 py-1 bg-blue-600 text-white rounded-md hover:bg-blue-700 text-sm"
          >
            <Plus className="w-4 h-4" />
            <span>Add Feature</span>
          </button>
        </div>

        <div className="space-y-4 max-h-96 overflow-y-auto">
          {features.map((feature: any, index: number) => (
            <div
              key={feature.id}
              className="p-4 border border-gray-200 dark:border-gray-600 rounded-lg bg-gray-50 dark:bg-gray-800"
            >
              <div className="flex items-center justify-between mb-3">
                <span className="font-medium text-sm">Feature {index + 1}</span>
                <div className="flex items-center space-x-1">
                  <button
                    onClick={() => moveFeature(index, 'up')}
                    disabled={index === 0}
                    className="p-1 text-gray-500 hover:text-gray-700 disabled:opacity-50"
                    title="Move Up"
                  >
                    ↑
                  </button>
                  <button
                    onClick={() => moveFeature(index, 'down')}
                    disabled={index === features.length - 1}
                    className="p-1 text-gray-500 hover:text-gray-700 disabled:opacity-50"
                    title="Move Down"
                  >
                    ↓
                  </button>
                  <button
                    onClick={() => removeFeature(index)}
                    className="p-1 text-red-500 hover:text-red-700"
                    title="Delete Feature"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>

              <div className="space-y-3">
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="block text-xs font-medium mb-1">Title</label>
                    <input
                      type="text"
                      value={feature.title}
                      onChange={(e) => updateFeature(index, { title: e.target.value })}
                      className="w-full px-2 py-1 text-sm border border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-gray-700"
                      placeholder="Feature Title"
                    />
                  </div>

                  <div>
                    <label className="block text-xs font-medium mb-1">Key</label>
                    <input
                      type="text"
                      value={feature.key}
                      onChange={(e) => updateFeature(index, { key: e.target.value })}
                      className="w-full px-2 py-1 text-sm border border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-gray-700"
                      placeholder="unique-key"
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-medium mb-1">Icon</label>
                  <select
                    value={feature.icon}
                    onChange={(e) => updateFeature(index, { icon: e.target.value })}
                    className="w-full px-2 py-1 text-sm border border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-gray-700"
                  >
                    {iconOptions.map((option) => (
                      <option key={option.value} value={option.value}>
                        {option.label}
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-xs font-medium mb-1">Preview Image URL</label>
                  <div className="flex space-x-2">
                    <input
                      type="text"
                      value={feature.previewImage}
                      onChange={(e) => updateFeature(index, { previewImage: e.target.value })}
                      className="flex-1 px-2 py-1 text-sm border border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-gray-700"
                      placeholder="/images/features/feature.png"
                    />
                    <button
                      className="px-2 py-1 bg-gray-200 dark:bg-gray-600 rounded hover:bg-gray-300 dark:hover:bg-gray-500"
                      title="Upload Image"
                    >
                      <Upload className="w-4 h-4" />
                    </button>
                  </div>
                </div>

                {data.showDescriptions && (
                  <div>
                    <label className="block text-xs font-medium mb-1">Description</label>
                    <textarea
                      value={feature.description || ''}
                      onChange={(e) => updateFeature(index, { description: e.target.value })}
                      className="w-full px-2 py-1 text-sm border border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-gray-700"
                      rows={2}
                      placeholder="Feature description..."
                    />
                  </div>
                )}

                {/* Preview */}
                {feature.previewImage && (
                  <div className="mt-2">
                    <div className="text-xs font-medium mb-1">Preview:</div>
                    <img
                      src={feature.previewImage}
                      alt={feature.title}
                      className="w-full h-20 object-cover rounded border"
                      onError={(e) => {
                        (e.target as HTMLImageElement).style.display = 'none';
                      }}
                    />
                  </div>
                )}
              </div>
            </div>
          ))}

          {features.length === 0 && (
            <div className="text-center py-8 text-gray-500 dark:text-gray-400">
              <div className="text-4xl mb-2">🎯</div>
              <p className="text-sm">No features added yet</p>
              <p className="text-xs">Click "Add Feature" to get started</p>
            </div>
          )}
        </div>
      </div>

      {/* Default Active Feature */}
      {features.length > 0 && (
        <div>
          <label className="block text-sm font-medium mb-2">Default Active Feature</label>
          <select
            value={data.defaultActiveFeature || ''}
            onChange={(e) => updateData({ defaultActiveFeature: e.target.value })}
            className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-800"
          >
            <option value="">First Feature</option>
            {features.map((feature: any) => (
              <option key={feature.key} value={feature.key}>
                {feature.title}
              </option>
            ))}
          </select>
        </div>
      )}
    </div>
  );
}

export default InteractiveFeatureWallPropertyPanel;